var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하핫! 여기 있었구나! 쥐새끼들아!","JPN":"ハハハ！　ここにいたのか！　ネズミども！","ENG":"Hahahaha! There you are! You little rats!","TWN":"哈哈哈！原來在這裡啊！鼠輩們！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"혹시나 네놈들을 이대로 놓쳐 버릴까 봐 얼마나 애가 탔는지 알아?","JPN":"てめえらをこのまま取り逃がしちまうと思って気が気じゃなかったぜ。","ENG":"Do you know how worried I was at the thought of losing you?","TWN":"如果就這樣放你們逃掉了，你們知道我可有多麼焦急啊。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그나저나 도망쳐도 모자랄 판에 제 발로 기어 들어오다니......","JPN":"それにしても、必死こいて逃げるチャンスなのに、自ら転がり込んでくるなんてな。","ENG":"But you've come to me on your own two feet...","TWN":"但明明逃跑都來不及了，還自己跑了回來……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"나에겐 다행스러운 일이지만, 역시 쥐새끼들 머릿속은 이해가 안 된다니까.","JPN":"アタシにとっちゃあラッキーなことなんだが、やっぱりネズミの頭の中は理解できないな。","ENG":"I'm not complaining, but I'll never understand what goes on in your measly little brains.","TWN":"雖然對我來說是大幸，但你們這些齧齒類的腦子在想什麼，還真是無法理解呢。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너...... 그때 그...... 테러리스트?","JPN":"あんたは……あの時の……テロリスト？","ENG":"You... You're that... Terrorist!","TWN":"妳……是那時候的……恐怖份子？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......꽤 강해 보이는 상대로군요, 스승님.","JPN":"……これは、手ごわそうな相手ですね、師匠。","ENG":"She looks pretty strong, Master...","TWN":"……看來是個強敵呢，師父。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"지금까지 만난 융합체인가 하는 괴물들과도 다른, 독특한 침식파가 느껴지네요.","JPN":"これまでの融合体とやらとも異なる、独特な侵食波が感じられますね。","ENG":"I'm sensing a unique Corruption ray that's different from those hybrider monsters.","TWN":"和至今我們遇到的融合體怪物不同，我感覺到了一股獨特的侵蝕波。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래...... 어떤 놈들인지는 모르겠지만, 아주 짜증나는 걸 만들어냈군.","JPN":"だな……正体はわからないが、実に忌々しいものを作り出したものだ。","ENG":"Yes... I'm not sure who they are, but they've created quite the beast.","TWN":"是啊……雖然我不知道她是什麼樣的傢伙，但是她搞出了一件非常麻煩的事。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 에이미! 에이미를 어떻게 한 거야?!","JPN":"それよりエイミー！　エイミーをどうしたんだ！","ENG":"Amy! What did you do to Amy!","TWN":"比起這個，艾米！艾米怎麼了！?"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"에이미? 그건 또 뭐야?","JPN":"エイミー？　何だそりゃ？","ENG":"Amy? What's that?","TWN":"艾米？這又是什麼？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"아, 혹시 이거?","JPN":"あ、もしかして、これのことか？","ENG":"Oh! You mean this?","TWN":"啊？妳說這個啊？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"하하, 이거 미안해서 어쩌나.","JPN":"ハハ、こりゃ悪かったな。","ENG":"Haha! I'm so sorry...","TWN":"哈哈，這真是抱歉哪，怎麼辦？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"쥐새끼답게 한 번 밟았더니 아주 박살이 나 버렸는데?","JPN":"ネズミらしく、たった一度踏んづけただけでメチャクチャになっちゃったよ。","ENG":"I just stepped on the little rat and she got crushed in an instant!","TWN":"她像隻老鼠一樣，被我踩得稀巴爛了耶？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"그러게 쥐새끼가 사람들 다니는 길에 얼쩡거리면 안 되지.","JPN":"ネズミなんかが人間様の通り道をうろうろするから、こうなるんだよ。","ENG":"That's why little rats should stay out of the people's way.","TWN":"老鼠就不要在人家走的路上閒晃啊！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너!!","JPN":"お前！！","ENG":"You...","TWN":"妳……！！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"시끄러워, 쥐새끼야.","JPN":"やかましいな、ネズミめ。","ENG":"Shut up, you little rat.","TWN":"吵死了，老鼠。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_NULL_NULL","text":{"KOREA":"너도 밟혀 죽기 싫으면 당장......","JPN":"てめえも踏んづけられたくなけりゃ、今すぐ……","ENG":"Unless you want to end up like her...","TWN":"如果妳也不想被踩死的話，馬上就給我……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};